#include <stdio.h>
#include <stdlib.h> // Required for malloc!

int main() {
    // Ask the user how many slots they need
    int numPlayers = 5; 

    // malloc( total bytes needed ). 
    // An int is usually 4 bytes, so 5 * 4 = 20 Bytes.
    int *scores = malloc(numPlayers * sizeof(int));

    // Treat the pointer EXACTLY like a normal array!
    scores[0] = 100;
    printf("Player 1 score: %d\n", scores[0]);

    return 0;
}
